const fs = require('fs');
const path = require('path');

// Test results storage
const results = {
  total: 0,
  passed: 0,
  failed: 0,
  suites: []
};

let currentSuite = null;

function describe(name, fn) {
  currentSuite = { name, tests: [], passed: 0, failed: 0 };
  fn();
  results.suites.push(currentSuite);
  currentSuite = null;
}

function test(name, fn) {
  results.total++;
  const testResult = { name, status: 'passed', error: null };
  
  try {
    fn();
    results.passed++;
    currentSuite.passed++;
    testResult.status = 'passed';
    process.stdout.write('✅');
  } catch (error) {
    results.failed++;
    currentSuite.failed++;
    testResult.status = 'failed';
    testResult.error = error.message;
    process.stdout.write('❌');
  }
  
  currentSuite.tests.push(testResult);
}

function expect(actual) {
  return {
    toBe(expected) {
      if (actual !== expected) throw new Error(`Expected ${expected}, got ${actual}`);
    },
    toEqual(expected) {
      if (JSON.stringify(actual) !== JSON.stringify(expected)) {
        throw new Error(`Expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
      }
    },
    toBeDefined() {
      if (actual === undefined) throw new Error('Expected value to be defined');
    },
    toContain(expected) {
      if (!actual.includes(expected)) throw new Error(`Expected to contain "${expected}"`);
    }
  };
}

// Adapter implementations
class BundleAdapter {
  constructor(wantParams) {
    this.params = new Map();
    if (wantParams) {
      Object.entries(wantParams).forEach(([key, value]) => {
        this.params.set(key, value);
      });
    }
  }
  put(key, value) { this.params.set(key, value); }
  get(key) { return this.params.get(key); }
  getString(key, defaultValue) {
    const value = this.params.get(key);
    return value !== undefined ? String(value) : defaultValue;
  }
  getInt(key, defaultValue) {
    const value = this.params.get(key);
    return value !== undefined ? parseInt(value, 10) : defaultValue;
  }
  containsKey(key) { return this.params.has(key); }
  keySet() { return Array.from(this.params.keys()); }
  isEmpty() { return this.params.size === 0; }
  size() { return this.params.size; }
  toWantParams() {
    const result = {};
    this.params.forEach((value, key) => { result[key] = value; });
    return result;
  }
}

class ButtonAdapter {
  constructor(text = '') {
    this.text = text;
    this.enabled = true;
    this.clickListener = null;
  }
  setText(text) { this.text = text; }
  getText() { return this.text; }
  setEnabled(enabled) { this.enabled = enabled; }
  isEnabled() { return this.enabled; }
  setOnClickListener(listener) { this.clickListener = listener; }
  performClick() {
    if (this.clickListener && this.enabled) this.clickListener();
  }
}

class TextViewAdapter {
  constructor(text = '') {
    this.text = text;
    this.textSize = 16;
  }
  setText(text) { this.text = String(text); }
  getText() { return this.text; }
  setTextSize(size) { this.textSize = size; }
  getTextSize() { return this.textSize; }
}

class TimeZoneAdapter {
  constructor(timeZoneId) {
    this.timeZoneId = timeZoneId || 'UTC';
  }
  static getDefault() {
    return new TimeZoneAdapter('Asia/Shanghai');
  }
  getID() { return this.timeZoneId; }
  getDisplayName() { return 'CST'; }
}

class EventAdapter {
  constructor() {
    this.listeners = new Map();
  }
  setOnClickListener(id, listener) {
    if (!this.listeners.has(id)) {
      this.listeners.set(id, []);
    }
    this.listeners.get(id).push(listener);
  }
  triggerClick(id) {
    const listeners = this.listeners.get(id) || [];
    listeners.forEach(listener => listener());
  }
}

