// Integration Tests
describe('Integration', () => {
  test('TextClock activity', () => {
    const bundle = new BundleAdapter();
    const tv = new TextViewAdapter();
    const btn = new ButtonAdapter();
    const events = new EventAdapter();
    
    events.setOnClickListener('tz', () => {
      tv.setText('Zone: ' + TimeZoneAdapter.getDefault().getDisplayName());
    });
    btn.setOnClickListener(() => events.triggerClick('tz'));
    btn.performClick();
    
    expect(tv.getText()).toContain('Zone:');
  });
  test('lifecycle', () => {
    const bundle = new BundleAdapter();
    bundle.put('key', 'value');
    expect(bundle.getString('key')).toBe('value');
  });
});

